import { memo } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Link } from "react-router-dom";
import { Sparkles, MapPin } from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";

interface GuessYouLikeProps {
  currentId: string;
  city?: string | null;
  template?: string;
  limit?: number;
}

const GuessYouLike = memo(({ currentId, city, template, limit = 6 }: GuessYouLikeProps) => {
  const { t, i18n } = useTranslation();
  const lang = i18n.language;

  const { data: items, isLoading } = useQuery({
    queryKey: ["guess-you-like", currentId, city, template],
    queryFn: async () => {
      let query = supabase
        .from("restaurants")
        .select("id, name, name_en, name_pt, image_url, city, template, type, type_en")
        .eq("visible", true)
        .neq("id", currentId)
        .not("image_url", "is", null)
        .limit(limit);

      if (city) query = query.eq("city", city);
      if (template) query = query.eq("template", template);

      // Order by random-ish: created_at desc gives variety
      query = query.order("created_at", { ascending: false });

      const { data, error } = await query;
      if (error) throw error;

      // Shuffle for randomness
      return (data || []).sort(() => Math.random() - 0.5).slice(0, limit);
    },
    staleTime: 1000 * 60 * 5,
  });

  const getName = (r: any) => {
    if (lang === "zh") return r.name;
    if (lang === "pt") return r.name_pt || r.name_en || r.name;
    return r.name_en || r.name;
  };

  if (isLoading) {
    return (
      <div className="mt-8">
        <div className="flex items-center gap-2 mb-4">
          <Skeleton className="w-5 h-5 rounded" />
          <Skeleton className="w-32 h-5" />
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
          {Array.from({ length: limit }).map((_, i) => (
            <Skeleton key={i} className="aspect-[4/3] rounded-lg" />
          ))}
        </div>
      </div>
    );
  }

  if (!items || items.length === 0) return null;

  return (
    <div className="mt-8">
      <div className="flex items-center gap-2 mb-4">
        <Sparkles className="w-5 h-5 text-primary" />
        <h3 className="text-base font-semibold text-foreground">
          {t("recommendations.guessYouLike")}
        </h3>
      </div>
      <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
        {items.map((item) => (
          <Link
            key={item.id}
            to={`/restaurant/${item.id}`}
            className="group relative rounded-lg overflow-hidden border border-border/50 hover:border-primary/30 transition-colors"
          >
            <div className="aspect-[4/3] bg-muted">
              <img
                src={item.image_url!}
                alt={getName(item)}
                loading="lazy"
                className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
              />
            </div>
            <div className="absolute inset-x-0 bottom-0 bg-gradient-to-t from-black/70 to-transparent p-2">
              <p className="text-xs font-medium text-white truncate">
                {getName(item)}
              </p>
              {item.city && (
                <p className="text-[10px] text-white/70 flex items-center gap-0.5 mt-0.5">
                  <MapPin className="w-2.5 h-2.5" />
                  {item.city}
                </p>
              )}
            </div>
          </Link>
        ))}
      </div>
    </div>
  );
});

GuessYouLike.displayName = "GuessYouLike";

export default GuessYouLike;
